prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?modelId WHERE {
  ?model a bboExt:Model .
  ?model bbo:name ?modelName .
  OPTIONAL { ?model tai:normalizedId ?modelId . }
  OPTIONAL { ?model tai:originalId ?modelId . }
  FILTER(CONTAINS(STR(?modelId), "4e8df28e6d9f4afe970d06522542e830"))
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?modelId ?origId WHERE {
  ?model a bboExt:Model .
  ?model bbo:name ?modelName .
  OPTIONAL { ?model tai:normalizedId ?modelId . }
  OPTIONAL { ?model tai:originalId ?origId . }
}
LIMIT 50

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gw ?gwName ?dir (COUNT(?incoming) AS ?in) (COUNT(?outgoing) AS ?out) WHERE {
  ?choreo a bboExt:Choreography .
  FILTER(CONTAINS(STR(?choreo), "sid_dd7a27c7_a916_41b5_a596_d1a83c30cef2"))
  ?gw a bboExt:ExclusiveGateway .
  ?gw bbo:name ?gwName .
  OPTIONAL { ?gw bboExt:gatewayDirection ?dir . }
  ?gw tai:belongsTo ?choreo .
  OPTIONAL { ?incoming a bbo:SequenceFlow . ?incoming bbo:has_targetRef ?gw . }
  OPTIONAL { ?outgoing a bbo:SequenceFlow . ?outgoing bbo:has_sourceRef ?gw . }
}
GROUP BY ?gw ?gwName ?dir
